const allData = $("Nova Era Request").first().json;

function extractLastDigit(accountString) {
    if (!accountString || accountString.length < 2) {
        return null;
    }
    return {
        conta: accountString.slice(0, -1),
        digito: accountString.slice(-1)
    };
}

function orgaov(allData) {
  if (allData.Rmc.Banco === "318") {
    return 9
  } else if (allData.RCC.Banco === "318") {
    return 39
  }
}

const splitedConta = extractLastDigit(allData.DadosBancarios.ContaPagto)

const dadosConta = {
  ...allData.DadosBancarios,
  "conta": splitedConta?.conta,
  "digito": splitedConta?.digito
}


return {
  "contaBancaria": dadosConta ? dadosConta : {},
  "beneficiario": allData.Beneficiario,
  "resumoFinanceiro": allData.ResumoFinanceiro,
  "orgao_agilus": orgaov(allData)
}

